// Merge the Claude analysis with the original call metadata and transcript
const call = $('Set Call Metadata').item.json;
const transcript = $('Transcribe Audio with Whisper').item.json.text || '';
const raw = $json.content?.[0]?.text || '{}';

let parsed = {
  caller_name: '',
  intent: 'other',
  summary: 'Failed to parse AI response',
  service_or_topic: '',
  urgency: 'low',
  callback_needed: false,
  sentiment: 'neutral'
};

try {
  const cleaned = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed.summary = 'AI returned malformed JSON: ' + raw.slice(0, 200);
}

const isUrgent = parsed.urgency === 'high' || parsed.intent === 'complaint';

return [{
  json: {
    ...call,
    transcript,
    caller_name: parsed.caller_name || '',
    intent: parsed.intent,
    summary: parsed.summary,
    service_or_topic: parsed.service_or_topic || '',
    urgency: parsed.urgency,
    callback_needed: parsed.callback_needed === true,
    sentiment: parsed.sentiment,
    isUrgent
  }
}];
